import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: string;
  forecast?: ForecastDay[];
}

export default function GeneratedComponent(props: Props) {
  const {
    city = "Unknown City",
    temperature = 0,
    condition = "Unknown",
    humidity = 0,
    windSpeed = 0,
    unit = "C",
    forecast = [],
  } = props;

  const weatherEmoji = condition.toLowerCase().includes('sun') 
    ? '☀️' 
    : condition.toLowerCase().includes('cloud') 
    ? '⛅' 
    : condition.toLowerCase().includes('rain') 
    ? '🌧️' 
    : '🌡️';

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={24}>
        <Stack gap={4}>
          <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">CURRENT LOCATION</Text>
          <Heading level={2}>{city}</Heading>
        </Stack>

        <Stack direction="horizontal" align="center" justify="between">
          <Stack gap={0}>
            <Text size="4xl" weight="bold">
              {temperature}°{unit}
            </Text>
            <Text variant="bodyLarge" color="var(--ggui-color-neutral-600, #4b5563)">{condition}</Text>
          </Stack>
          <Text size="4xl">{weatherEmoji}</Text>
        </Stack>

        <Box background="var(--ggui-color-neutral-100, #f3f4f6)" padding={16} borderRadius={8}>
          <Stack direction="horizontal" justify="between">
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">HUMIDITY</Text>
              <Text weight="semibold">{humidity}%</Text>
            </Stack>
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">WIND</Text>
              <Text weight="semibold">{windSpeed} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-neutral-200, #e5e7eb)" />

        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Stack key={index} gap={4} align="center">
              <Text variant="label">{item.day ?? '—'}</Text>
              <Text>{item.icon ?? '?'}</Text>
              <Stack gap={4} direction="horizontal">
                <Text variant="bodySmall" weight="semibold">{item.high ?? 0}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{item.low ?? 0}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { Container, Stack, Box, Card, Text, Heading, Input, Divider } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements?: ElementData[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
  'alkali-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'transition-metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'metalloid': 'var(--ggui-color-success-100, #dcfce7)',
  'halogen': 'var(--ggui-color-error-100, #fee2e2)',
  'lanthanide': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'actinide': 'var(--ggui-color-neutral-300, #d1d5db)',
  'post-transition-metal': 'var(--ggui-color-primary-300, #7dd3fc)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const filteredElements = elements.filter(
    (el) =>
      el.name?.toLowerCase().includes(search.toLowerCase()) ||
      el.symbol?.toLowerCase().includes(search.toLowerCase())
  );

  const categories = Array.from(new Set(elements.map((el) => el.category || 'unknown')));

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Input 
          label="Search Elements" 
          type="search" 
          value={search} 
          onChange={setSearch} 
          placeholder="Enter name or symbol..." 
        />

        <Box 
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            alignItems: 'start'
          }}
        >
          {filteredElements.map((el) => (
            <Box
              key={el.atomicNumber}
              onClick={() => setSelected(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                backgroundColor: CATEGORY_COLORS[el.category || ''] || 'var(--ggui-color-neutral-100, #f3f4f6)',
                cursor: 'pointer',
                aspectRatio: '1/1',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                opacity: search && !el.name?.toLowerCase().includes(search.toLowerCase()) && !el.symbol?.toLowerCase().includes(search.toLowerCase()) ? 0.3 : 1
              }}
            >
              <Text variant="caption">{el.atomicNumber}</Text>
              <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>{el.symbol}</Text>
            </Box>
          ))}
        </Box>

        {selected && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
            <Heading level={3}>{selected.name}</Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)">
              <Text>Symbol: <strong>{selected.symbol}</strong></Text>
              <Text>Atomic Number: <strong>{selected.atomicNumber}</strong></Text>
              <Text>Weight: <strong>{selected.atomicWeight}</strong></Text>
              <Text>Category: <strong>{selected.category}</strong></Text>
            </Stack>
          </Card>
        )}

        <Divider margin="var(--ggui-spacing-4, 16px)" />

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {categories.map(cat => (
            <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Box style={{ width: 16, height: 16, backgroundColor: CATEGORY_COLORS[cat] || 'var(--ggui-color-neutral-100, #f3f4f6)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)' }} />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'London',
    temperature = 20,
    condition = 'Cloudy',
    humidity = 60,
    windSpeed = 10,
    unit = 'C',
    forecast = [
      { day: 'Mon', icon: '☀️', high: 22, low: 15 },
      { day: 'Tue', icon: '⛅', high: 20, low: 14 },
      { day: 'Wed', icon: '🌧️', high: 18, low: 12 },
      { day: 'Thu', icon: '☁️', high: 19, low: 13 },
      { day: 'Fri', icon: '☀️', high: 23, low: 16 },
    ],
  } = props;

  return (
    <Card padding={24} shadow="md" radius="lg" style={{ width: '100%', maxWidth: '400px' }}>
      <Stack gap={24}>
        {/* Header: City & Condition */}
        <Stack gap={4} align="center">
          <Heading level={2}>{city ?? 'Unknown City'}</Heading>
          <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
            {condition ?? 'N/A'}
          </Text>
        </Stack>

        {/* Current Temp */}
        <Stack align="center" gap={4}>
          <Text size="4xl" weight="bold">
            {temperature}°{unit}
          </Text>
        </Stack>

        {/* Stats */}
        <Stack direction="horizontal" justify="center" gap={32}>
          <Stack gap={4} align="center">
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
            <Text weight="medium">{humidity}%</Text>
          </Stack>
          <Stack gap={4} align="center">
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Wind</Text>
            <Text weight="medium">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={0} />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center">
          {(forecast ?? []).map((item, index) => (
            <Stack key={index} gap={8} align="center">
              <Text variant="caption" weight="medium">{item.day ?? '-'}</Text>
              <Text size="xl">{item.icon ?? '?'}</Text>
              <Stack gap={2} align="center">
                <Text variant="bodySmall" weight="semibold">{item.high}°</Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{item.low}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input, Divider } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-success-100, #dcfce7)',
  'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
  'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition-metal': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'metalloid': 'var(--ggui-color-primary-50, #f0f9ff)',
  'halogen': 'var(--ggui-color-error-50, #fee2e2)',
  'lanthanide': 'var(--ggui-color-warning-50, #fffbeb)',
  'actinide': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'unknown': 'var(--ggui-color-neutral-100, #f3f4f6)'
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    const s = search.toLowerCase();
    return elements.filter(el => 
      el.name?.toLowerCase().includes(s) || 
      el.symbol?.toLowerCase().includes(s)
    );
  }, [elements, search]);

  const categories = Array.from(new Set(elements.map(e => e.category || 'unknown')));

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Card padding={16}>
          <Input 
            label="Search Elements"
            placeholder="Name or symbol (e.g. Hydrogen or H)" 
            value={search} 
            onChange={setSearch} 
          />
        </Card>

        <Card padding={16}>
          <Stack direction="horizontal" gap={16} wrap>
            {categories.map(cat => (
              <Stack key={cat} direction="horizontal" gap={8} align="center">
                <Box background={CATEGORY_COLORS[cat] || CATEGORY_COLORS['unknown']} borderRadius={4} padding={8} />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Card>

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: '4px',
            maxWidth: '1200px',
            margin: '0 auto'
          }}
        >
          {elements.map((el, i) => {
            const isFiltered = search && !el.name?.toLowerCase().includes(search.toLowerCase()) && !el.symbol?.toLowerCase().includes(search.toLowerCase());
            return (
              <div
                key={i}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  cursor: 'pointer',
                  opacity: isFiltered ? 0.3 : 1
                }}
              >
                <Card 
                  padding={8} 
                  radius="sm"
                  style={{ 
                    background: CATEGORY_COLORS[el.category || 'unknown'],
                    height: '80px',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center'
                  }}
                >
                  <Text variant="caption" style={{ alignSelf: 'flex-start' }}>{el.atomicNumber}</Text>
                  <Heading level={4}>{el.symbol}</Heading>
                </Card>
              </div>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding={24} shadow="md">
            <Stack gap={12}>
              <Heading level={2}>{selectedElement.name} ({selectedElement.symbol})</Heading>
              <Divider />
              <Stack direction="horizontal" gap={32}>
                <Stack gap={4}>
                  <Text variant="overline">Atomic Number</Text>
                  <Text>{selectedElement.atomicNumber}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="overline">Atomic Weight</Text>
                  <Text>{selectedElement.atomicWeight}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="overline">Category</Text>
                  <Text>{selectedElement.category}</Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
